   268→  void onUnderlyingConnectionBelowWriteBufferLowWatermark() override { onBelowLowWatermark(); }
   269→
   270→  // Codec errors found in callbacks are overridden within the http_parser library. This holds those
   271→  // errors to propagate them through to dispatch() where we can handle the error.
   272→  Envoy::Http::Status codec_status_;
   273→
   274→  // ScopeTrackedObject
   275→  ExecutionContext* executionContext() const override;
   276→  void dumpState(std::ostream& os, int indent_level) const override;
   277→
   278→protected:
   279→  ConnectionImpl(Network::Connection& connection, CodecStats& stats, const Http1Settings& settings,
   280→                 MessageType type, uint32_t max_headers_kb, const uint32_t max_headers_count);
   281→
   282→  bool resetStreamCalled() { return reset_stream_called_; }
   283→
   284→  // This must be protected because it is called through ServerConnectionImpl::sendProtocolError.
   285→  Status onMessageBeginImpl();
   286→
   287→  /**
   288→   * Get memory used to represent HTTP headers or trailers currently being parsed.
   289→   * Computed by adding the partial header field and value that is currently being parsed and the
   290→   * estimated header size for previous header lines provided by HeaderMap::byteSize().
   291→   */
   292→  virtual uint32_t getHeadersSize();
   293→
   294→  /**
   295→   * Called from onUrl, onHeaderFields and onHeaderValue to verify that the headers do not exceed
   296→   * the configured max header size limit.
   297→   * @return A codecProtocolError status if headers exceed the size limit.
   298→   */
   299→  Status checkMaxHeadersSize();
   300→
   301→  Network::Connection& connection_;
   302→  CodecStats& stats_;
   303→  const Http1Settings codec_settings_;
   304→  std::unique_ptr<Parser> parser_;
   305→  Buffer::Instance* current_dispatching_buffer_{};
   306→  Buffer::Instance* output_buffer_ = nullptr; // Not owned
   307→  Http::Code error_code_{Http::Code::BadRequest};
   308→  const HeaderKeyFormatterConstPtr encode_only_header_key_formatter_;
   309→  HeaderString current_header_field_;
   310→  HeaderString current_header_value_;
   311→  bool processing_trailers_ : 1;
   312→  bool handling_upgrade_ : 1;
   313→  bool reset_stream_called_ : 1;
   314→  // Deferred end stream headers indicate that we are not going to raise headers until the full
   315→  // HTTP/1 message has been flushed from the parser. This allows raising an HTTP/2 style headers
   316→  // block with end stream set to true with no further protocol data remaining.
   317→  bool deferred_end_stream_headers_ : 1;
   318→  bool dispatching_ : 1;
   319→  bool dispatching_slice_already_drained_ : 1;
   320→  StreamInfo::BytesMeterSharedPtr bytes_meter_before_stream_;
   321→  const uint32_t max_headers_kb_;
   322→  const uint32_t max_headers_count_;
   323→
   324→private:
   325→  enum class HeaderParsingState { Field, Value, Done };
   326→  friend std::ostream& operator<<(std::ostream& os, HeaderParsingState parsing_state) {
   327→    switch (parsing_state) {
   328→    case ConnectionImpl::HeaderParsingState::Field:
   329→      return os << "Field";
   330→    case ConnectionImpl::HeaderParsingState::Value:
   331→      return os << "Value";
   332→    case ConnectionImpl::HeaderParsingState::Done:
   333→      return os << "Done";
   334→    }
   335→    return os;
   336→  }
   337→
   338→  virtual HeaderMap& headersOrTrailers() PURE;
   339→  virtual RequestOrResponseHeaderMap& requestOrResponseHeaders() PURE;
   340→  virtual void allocHeaders(StatefulHeaderKeyFormatterPtr&& formatter) PURE;
   341→  virtual void allocTrailers() PURE;
   342→
   343→  /**
   344→   * Called for each header in order to complete an in progress header decode.
   345→   * @return A status representing success.
   346→   */
   347→  Status completeCurrentHeader();
   348→
   349→  /**
   350→   * Check if header name contains underscore character.
   351→   * Underscore character is allowed in header names by the RFC-7230 and this check is implemented
   352→   * as a security measure due to systems that treat '_' and '-' as interchangeable.
   353→   * The ServerConnectionImpl may drop header or reject request based on the
   354→   * `common_http_protocol_options.headers_with_underscores_action` configuration option in the
   355→   * HttpConnectionManager.
   356→   */
   357→  virtual bool shouldDropHeaderWithUnderscoresInNames(absl::string_view /* header_name */) const {
   358→    return false;
   359→  }
   360→
   361→  /**
   362→   * Dispatch a memory span.
   363→   * @param slice supplies the start address.
   364→   * @len supplies the length of the span.
   365→   */
   366→  Envoy::StatusOr<size_t> dispatchSlice(const char* slice, size_t len);
   367→
   368→  void onDispatch(const Buffer::Instance& data);
   369→
   370→  // ParserCallbacks.
   371→  CallbackResult onMessageBegin() override;
   372→  CallbackResult onUrl(const char* data, size_t length) override;
   373→  CallbackResult onStatus(const char* data, size_t length) override;
   374→  CallbackResult onHeaderField(const char* data, size_t length) override;
   375→  CallbackResult onHeaderValue(const char* data, size_t length) override;
   376→  CallbackResult onHeadersComplete() override;
   377→  void bufferBody(const char* data, size_t length) override;
   378→  CallbackResult onMessageComplete() override;
   379→  void onChunkHeader(bool is_final_chunk) override;
   380→
   381→  // Internal implementations of ParserCallbacks methods,
   382→  // and virtual methods for connection-specific implementations.
   383→  virtual Status onMessageBeginBase() PURE;
   384→  virtual Status onUrlBase(const char* data, size_t length) PURE;
   385→  virtual Status onStatusBase(const char* data, size_t length) PURE;
   386→  Status onHeaderFieldImpl(const char* data, size_t length);
   387→  Status onHeaderValueImpl(const char* data, size_t length);
   388→  StatusOr<CallbackResult> onHeadersCompleteImpl();
   389→  virtual StatusOr<CallbackResult> onHeadersCompleteBase() PURE;
   390→  StatusOr<CallbackResult> onMessageCompleteImpl();
   391→  virtual CallbackResult onMessageCompleteBase() PURE;
   392→
   393→  // These helpers wrap *Impl() calls in the overrides of non-void
   394→  // ParserCallbacks methods.
   395→  CallbackResult setAndCheckCallbackStatus(Status&& status);
   396→  CallbackResult setAndCheckCallbackStatusOr(StatusOr<CallbackResult>&& statusor);
   397→
   398→  /**
   399→   * Push the accumulated body through the filter pipeline.
   400→   */
   401→  void dispatchBufferedBody();
   402→
   403→  /**
   404→   * Called to see if upgrade transition is allowed.
   405→   */
   406→  virtual bool upgradeAllowed() const PURE;
   407→
   408→  /**
   409→   * Called with body data is available for processing when either:
   410→   * - There is an accumulated partial body after the parser is done processing bytes read from the
   411→   * socket
   412→   * - The parser encounters the last byte of the body
   413→   * - The codec does a direct dispatch from the read buffer
   414→   * For performance reasons there is at most one call to onBody per call to HTTP/1
   415→   * ConnectionImpl::dispatch call.
   416→   * @param data supplies the body data
   417→   */
   418→  virtual void onBody(Buffer::Instance& data) PURE;
   419→
   420→  /**
   421→   * @see onResetStreamBase().
   422→   */
   423→  virtual void onResetStream(StreamResetReason reason) PURE;
   424→
   425→  /**
   426→   * Send a protocol error response to remote.
   427→   */
   428→  virtual Status sendProtocolError(absl::string_view details) PURE;
   429→
   430→  /**
   431→   * Called when output_buffer_ or the underlying connection go from below a low watermark to over
   432→   * a high watermark.
   433→   */
   434→  virtual void onAboveHighWatermark() PURE;
   435→
   436→  /**
   437→   * Called when output_buffer_ or the underlying connection  go from above a high watermark to
   438→   * below a low watermark.
   439→   */
   440→  virtual void onBelowLowWatermark() PURE;
   441→
   442→  /**
   443→   * Check if header name contains underscore character.
   444→   * The ServerConnectionImpl may drop header or reject request based on configuration.
   445→   * @return A status representing whether the request is rejected.
   446→   */
   447→  virtual Status checkHeaderNameForUnderscores() { return okStatus(); }
   448→
   449→  /**
   450→   * Additional state to dump on crash.
   451→   */
   452→  virtual void dumpAdditionalState(std::ostream& os, int indent_level) const PURE;
   453→
   454→  HeaderParsingState header_parsing_state_{HeaderParsingState::Field};
   455→  // Used to accumulate the HTTP message body during the current dispatch call. The accumulated body
   456→  // is pushed through the filter pipeline either at the end of the current dispatch call, or when
   457→  // the last byte of the body is processed (whichever happens first).
   458→  Buffer::OwnedImpl buffered_body_;
   459→  Protocol protocol_{Protocol::Http11};
   460→};
   461→
   462→/**
   463→ * Implementation of Http::ServerConnection for HTTP/1.1.
   464→ */
   465→class ServerConnectionImpl : public ServerConnection, public ConnectionImpl {
   466→public:
   467→  ServerConnectionImpl(Network::Connection& connection, CodecStats& stats,
   468→                       ServerConnectionCallbacks& callbacks, const Http1Settings& settings,
   469→                       uint32_t max_request_headers_kb, const uint32_t max_request_headers_count,
   470→                       envoy::config::core::v3::HttpProtocolOptions::HeadersWithUnderscoresAction
   471→                           headers_with_underscores_action,
   472→                       Server::OverloadManager& overload_manager);
   473→  bool supportsHttp10() override { return codec_settings_.accept_http_10_; }
   474→
   475→protected:
   476→  /**
   477→   * An active HTTP/1.1 request.
   478→   */
   479→  struct ActiveRequest : public Event::DeferredDeletable {
   480→    ActiveRequest(ServerConnectionImpl& connection, StreamInfo::BytesMeterSharedPtr&& bytes_meter)
   481→        : response_encoder_(connection, std::move(bytes_meter),
   482→                            connection.codec_settings_.stream_error_on_invalid_http_message_) {}
   483→    ~ActiveRequest() override = default;
   484→
   485→    void dumpState(std::ostream& os, int indent_level) const;
   486→    HeaderString request_url_;
   487→    RequestDecoder* request_decoder_{};
   488→    ResponseEncoderImpl response_encoder_;
   489→    bool remote_complete_{};
   490→  };
   491→  ActiveRequest* activeRequest() { return active_request_.get(); }
   492→  // ConnectionImpl
   493→  CallbackResult onMessageCompleteBase() override;
   494→  // Add the size of the request_url to the reported header size when processing request headers.
   495→  uint32_t getHeadersSize() override;
   496→
   497→private:
   498→  /**
   499→   * Manipulate the request's first line, parsing the url and converting to a relative path if
   500→   * necessary. Compute Host / :authority headers based on 7230#5.7 and 7230#6
   501→   *
   502→   * @param is_connect true if the request has the CONNECT method
   503→   * @param headers the request's headers
   504→   * @return Status representing success or failure. This will fail if there is an invalid url in
   505→   * the request line.
   506→   */
   507→  Status handlePath(RequestHeaderMap& headers, absl::string_view method);
   508→
   509→  // ParserCallbacks.
   510→  Status onUrlBase(const char* data, size_t length) override;
   511→  Status onStatusBase(const char*, size_t) override { return okStatus(); }
   512→  // ConnectionImpl
   513→  Http::Status dispatch(Buffer::Instance& data) override;
   514→  void onEncodeComplete() override;
   515→  StreamInfo::BytesMeter& getBytesMeter() override {
   516→    if (active_request_) {
   517→      return *(active_request_->response_encoder_.getStream().bytesMeter());
   518→    }
   519→    if (bytes_meter_before_stream_ == nullptr) {
   520→      bytes_meter_before_stream_ = std::make_shared<StreamInfo::BytesMeter>();
   521→    }
   522→    return *bytes_meter_before_stream_;
   523→  }
   524→  Status onMessageBeginBase() override;
   525→  Envoy::StatusOr<CallbackResult> onHeadersCompleteBase() override;
   526→  // If upgrade behavior is not allowed, the HCM will have sanitized the headers out.
   527→  bool upgradeAllowed() const override { return true; }
   528→  void onBody(Buffer::Instance& data) override;
   529→  void onResetStream(StreamResetReason reason) override;
   530→  Status sendProtocolError(absl::string_view details) override;
   531→  Status sendOverloadError();
   532→  void onAboveHighWatermark() override;
   533→  void onBelowLowWatermark() override;
   534→  HeaderMap& headersOrTrailers() override {
   535→    if (absl::holds_alternative<RequestHeaderMapPtr>(headers_or_trailers_)) {
   536→      return *absl::get<RequestHeaderMapPtr>(headers_or_trailers_);
   537→    } else {
   538→      return *absl::get<RequestTrailerMapPtr>(headers_or_trailers_);
   539→    }
   540→  }
   541→  RequestOrResponseHeaderMap& requestOrResponseHeaders() override {
   542→    return *absl::get<RequestHeaderMapPtr>(headers_or_trailers_);
   543→  }
   544→  void allocHeaders(StatefulHeaderKeyFormatterPtr&& formatter) override {
   545→    ASSERT(nullptr == absl::get<RequestHeaderMapPtr>(headers_or_trailers_));
   546→    ASSERT(!processing_trailers_);
   547→    auto headers = RequestHeaderMapImpl::create(max_headers_kb_, max_headers_count_);
   548→    headers->setFormatter(std::move(formatter));
   549→    headers_or_trailers_.emplace<RequestHeaderMapPtr>(std::move(headers));
   550→  }
   551→  void allocTrailers() override {
   552→    ASSERT(processing_trailers_);
   553→    if (!absl::holds_alternative<RequestTrailerMapPtr>(headers_or_trailers_)) {
   554→      headers_or_trailers_.emplace<RequestTrailerMapPtr>(
   555→          RequestTrailerMapImpl::create(max_headers_kb_, max_headers_count_));
   556→    }
   557→  }
   558→  void dumpAdditionalState(std::ostream& os, int indent_level) const override;
   559→
   560→  void releaseOutboundResponse(const Buffer::OwnedBufferFragmentImpl* fragment);
   561→  void maybeAddSentinelBufferFragment(Buffer::Instance& output_buffer) override;
   562→
   563→  Status doFloodProtectionChecks() const;
   564→  Status checkHeaderNameForUnderscores() override;
   565→  Status checkProtocolVersion(RequestHeaderMap& headers);
   566→
   567→  ServerConnectionCallbacks& callbacks_;
   568→  std::unique_ptr<ActiveRequest> active_request_;
   569→  const Buffer::OwnedBufferFragmentImpl::Releasor response_buffer_releasor_;
   570→  uint32_t outbound_responses_{};
   571→  // Buffer used to encode the HTTP message before moving it to the network connection's output
   572→  // buffer. This buffer is always allocated, never nullptr.
   573→  Buffer::InstancePtr owned_output_buffer_;
   574→  // TODO(mattklein123): This should be a member of ActiveRequest but this change needs dedicated
   575→  // thought as some of the reset and no header code paths make this difficult. Headers are
   576→  // populated on message begin. Trailers are populated on the first parsed trailer field (if
   577→  // trailers are enabled). The variant is reset to null headers on message complete for assertion
   578→  // purposes.
   579→  absl::variant<RequestHeaderMapPtr, RequestTrailerMapPtr> headers_or_trailers_;
   580→  // The action to take when a request header name contains underscore characters.
   581→  const envoy::config::core::v3::HttpProtocolOptions::HeadersWithUnderscoresAction
   582→      headers_with_underscores_action_;
   583→  Server::LoadShedPoint* abort_dispatch_{nullptr};
   584→};
   585→
   586→/**
   587→ * Implementation of Http::ClientConnection for HTTP/1.1.
   588→ */
   589→class ClientConnectionImpl : public ClientConnection, public ConnectionImpl {
   590→public:
   591→  ClientConnectionImpl(Network::Connection& connection, CodecStats& stats,
   592→                       ConnectionCallbacks& callbacks, const Http1Settings& settings,
   593→                       const uint32_t max_response_headers_count,
   594→                       bool passing_through_proxy = false);
   595→  // Http::ClientConnection
   596→  RequestEncoder& newStream(ResponseDecoder& response_decoder) override;
   597→
   598→private:
   599→  struct PendingResponse {
   600→    PendingResponse(ConnectionImpl& connection, StreamInfo::BytesMeterSharedPtr&& bytes_meter,
   601→                    ResponseDecoder* decoder)
   602→        : encoder_(connection, std::move(bytes_meter)), decoder_(decoder) {}
   603→    RequestEncoderImpl encoder_;
   604→    ResponseDecoder* decoder_;
   605→  };
   606→
   607→  bool cannotHaveBody();
   608→
   609→  bool sendFullyQualifiedUrl() const override {
   610→    // Send fully qualified URLs either if the parent connection is configured to do so or this
   611→    // stream is passing through a proxy and the underlying transport is plaintext.
   612→    return ConnectionImpl::sendFullyQualifiedUrl() ||
   613→           (passing_through_proxy_ && !connection().ssl());
   614→  }
   615→
   616→  // ParserCallbacks.
   617→  Status onUrlBase(const char*, size_t) override { return okStatus(); }
   618→  Status onStatusBase(const char* data, size_t length) override;
   619→  // ConnectionImpl
   620→  Http::Status dispatch(Buffer::Instance& data) override;
   621→  void onEncodeComplete() override {}
   622→  StreamInfo::BytesMeter& getBytesMeter() override {
   623→    if (pending_response_.has_value()) {
   624→      return *(pending_response_->encoder_.getStream().bytesMeter());
   625→    }
   626→    if (bytes_meter_before_stream_ == nullptr) {
   627→      bytes_meter_before_stream_ = std::make_shared<StreamInfo::BytesMeter>();
   628→    }
   629→    return *bytes_meter_before_stream_;
   630→  }
   631→  Status onMessageBeginBase() override { return okStatus(); }
   632→  Envoy::StatusOr<CallbackResult> onHeadersCompleteBase() override;
   633→  bool upgradeAllowed() const override;
   634→  void onBody(Buffer::Instance& data) override;
   635→  CallbackResult onMessageCompleteBase() override;
   636→  void onResetStream(StreamResetReason reason) override;
   637→  Status sendProtocolError(absl::string_view details) override;
   638→  void onAboveHighWatermark() override;
   639→  void onBelowLowWatermark() override;
   640→  HeaderMap& headersOrTrailers() override {
   641→    if (absl::holds_alternative<ResponseHeaderMapPtr>(headers_or_trailers_)) {
   642→      return *absl::get<ResponseHeaderMapPtr>(headers_or_trailers_);
   643→    } else {
   644→      return *absl::get<ResponseTrailerMapPtr>(headers_or_trailers_);
   645→    }
   646→  }
   647→  RequestOrResponseHeaderMap& requestOrResponseHeaders() override {
   648→    return *absl::get<ResponseHeaderMapPtr>(headers_or_trailers_);
   649→  }
   650→  void allocHeaders(StatefulHeaderKeyFormatterPtr&& formatter) override {
   651→    ASSERT(nullptr == absl::get<ResponseHeaderMapPtr>(headers_or_trailers_));
   652→    ASSERT(!processing_trailers_);
   653→    auto headers = ResponseHeaderMapImpl::create(max_headers_kb_, max_headers_count_);
   654→    headers->setFormatter(std::move(formatter));
   655→    headers_or_trailers_.emplace<ResponseHeaderMapPtr>(std::move(headers));
   656→  }
   657→  void allocTrailers() override {
   658→    ASSERT(processing_trailers_);
   659→    if (!absl::holds_alternative<ResponseTrailerMapPtr>(headers_or_trailers_)) {
   660→      headers_or_trailers_.emplace<ResponseTrailerMapPtr>(
   661→          ResponseTrailerMapImpl::create(max_headers_kb_, max_headers_count_));
   662→    }
   663→  }
   664→  void dumpAdditionalState(std::ostream& os, int indent_level) const override;
   665→
   666→  // Buffer used to encode the HTTP message before moving it to the network connection's output
   667→  // buffer. This buffer is always allocated, never nullptr.
   668→  Buffer::InstancePtr owned_output_buffer_;
   669→
   670→  absl::optional<PendingResponse> pending_response_;
   671→  // TODO(mattklein123): The following bool tracks whether a pending response is complete before
   672→  // dispatching callbacks. This is needed so that pending_response_ stays valid during callbacks
   673→  // in order to access the stream, but to avoid invoking callbacks that shouldn't be called once
   674→  // the response is complete. The existence of this variable is hard to reason about and it should
   675→  // be combined with pending_response_ somehow in a follow up cleanup.
   676→  bool pending_response_done_{true};
   677→  // Set true between receiving non-101 1xx headers and receiving the spurious onMessageComplete.
   678→  bool ignore_message_complete_for_1xx_{};
   679→  // TODO(mattklein123): This should be a member of PendingResponse but this change needs dedicated
   680→  // thought as some of the reset and no header code paths make this difficult. Headers are
   681→  // populated on message begin. Trailers are populated when the switch to trailer processing is
   682→  // detected while parsing the first trailer field (if trailers are enabled). The variant is reset
   683→  // to null headers on message complete for assertion purposes.
   684→  absl::variant<ResponseHeaderMapPtr, ResponseTrailerMapPtr> headers_or_trailers_;
   685→
   686→  // True if the upstream connection is pointed at an HTTP/1.1 proxy, and
   687→  // plaintext HTTP should be sent with fully qualified URLs.
   688→  bool passing_through_proxy_ = false;
   689→};
