   438→static constexpr absl::string_view REQUEST_POSTFIX = " HTTP/1.1\r\n";
   439→
   440→Status RequestEncoderImpl::encodeHeaders(const RequestHeaderMap& headers, bool end_stream) {
   441→#ifndef ENVOY_ENABLE_UHV
   442→  // Headers are now validated by UHV before encoding by the codec. Two checks below are not needed
   443→  // when UHV is enabled.
   444→  //
   445→  // Required headers must be present. This can only happen by some erroneous processing after the
   446→  // downstream codecs decode.
   447→  RETURN_IF_ERROR(HeaderUtility::checkRequiredRequestHeaders(headers));
   448→  // Verify that a filter hasn't added an invalid header key or value.
   449→  RETURN_IF_ERROR(HeaderUtility::checkValidRequestHeaders(headers));
   450→#endif
   451→
   452→  const HeaderEntry* method = headers.Method();
   453→  const HeaderEntry* path = headers.Path();
   454→  const HeaderEntry* host = headers.Host();
   455→  bool is_connect = HeaderUtility::isConnect(headers);
   456→  const Http::HeaderValues& header_values = Http::Headers::get();
   457→
   458→  if (method->value() == header_values.MethodValues.Head) {
   459→    head_request_ = true;
   460→  } else if (method->value() == header_values.MethodValues.Connect) {
   461→    disableChunkEncoding();
   462→    connection_.connection().enableHalfClose(true);
   463→    connect_request_ = true;
   464→  }
   465→  if (Utility::isUpgrade(headers)) {
   466→    upgrade_request_ = true;
   467→    // If the flag is flipped from true to false all outstanding upgrade requests that are waiting
   468→    // for upstream connections will become invalid, as Envoy will add chunk encoding to the
   469→    // protocol stream. This will likely cause the server to disconnect, since it will be unable to
   470→    // parse the protocol.
   471→    disableChunkEncoding();
   472→  }
   473→
   474→  if (connection_.sendFullyQualifiedUrl() && !is_connect) {
   475→    const HeaderEntry* scheme = headers.Scheme();
   476→    if (!scheme) {
   477→      return absl::InvalidArgumentError(
   478→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Scheme.get()));
   479→    }
   480→    if (!host) {
   481→      return absl::InvalidArgumentError(
   482→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Host.get()));
   483→    }
   484→    ASSERT(path);
   485→    ASSERT(host);
   486→
   487→    std::string url = absl::StrCat(scheme->value().getStringView(), "://",
   488→                                   host->value().getStringView(), path->value().getStringView());
   489→    ENVOY_CONN_LOG(trace, "Sending fully qualified URL: {}", connection_.connection(), url);
   490→    connection_.buffer().addFragments(
   491→        {method->value().getStringView(), SPACE, url, REQUEST_POSTFIX});
   492→  } else {
   493→    absl::string_view host_or_path_view;
   494→    if (is_connect) {
   495→      host_or_path_view = host->value().getStringView();
   496→    } else {
   497→      host_or_path_view = path->value().getStringView();
   498→    }
   499→
   500→    connection_.buffer().addFragments(
   501→        {method->value().getStringView(), SPACE, host_or_path_view, REQUEST_POSTFIX});
   502→  }
   503→
   504→  encodeHeadersBase(headers, absl::nullopt, end_stream,
   505→                    HeaderUtility::requestShouldHaveNoBody(headers));
   506→  return okStatus();
   507→}
