   542→Status ConnectionImpl::completeCurrentHeader() {
   543→  ASSERT(dispatching_);
   544→  ENVOY_CONN_LOG(trace, "completed header: key={} value={}", connection_,
   545→                 current_header_field_.getStringView(), current_header_value_.getStringView());
   546→  auto& headers_or_trailers = headersOrTrailers();
   547→
   548→  // Account for ":" and "\r\n" bytes between the header key value pair.
   549→  getBytesMeter().addHeaderBytesReceived(CRLF_SIZE + 1);
   550→
   551→  // TODO(10646): Switch to use HeaderUtility::checkHeaderNameForUnderscores().
   552→  RETURN_IF_ERROR(checkHeaderNameForUnderscores());
   553→  if (!current_header_field_.empty()) {
   554→    // Strip trailing whitespace of the current header value if any. Leading whitespace was trimmed
   555→    // in ConnectionImpl::onHeaderValue. http_parser does not strip leading or trailing whitespace
   556→    // as the spec requires: https://tools.ietf.org/html/rfc7230#section-3.2.4
   557→    current_header_value_.rtrim();
   558→
   559→    // If there is a stateful formatter installed, remember the original header key before
   560→    // converting to lower case.
   561→    auto formatter = headers_or_trailers.formatter();
   562→    if (formatter.has_value()) {
   563→      formatter->processKey(current_header_field_.getStringView());
   564→    }
   565→    current_header_field_.inlineTransform([](char c) { return absl::ascii_tolower(c); });
   566→
   567→    headers_or_trailers.addViaMove(std::move(current_header_field_),
   568→                                   std::move(current_header_value_));
   569→  }
   570→
   571→  // Check if the number of headers exceeds the limit.
   572→  if (headers_or_trailers.size() > max_headers_count_) {
   573→    error_code_ = Http::Code::RequestHeaderFieldsTooLarge;
   574→    RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().TooManyHeaders));
   575→    const absl::string_view header_type =
   576→        processing_trailers_ ? Http1HeaderTypes::get().Trailers : Http1HeaderTypes::get().Headers;
   577→    return codecProtocolError(
   578→        absl::StrCat("http/1.1 protocol error: ", header_type, " count exceeds limit"));
   579→  }
   580→
   581→  header_parsing_state_ = HeaderParsingState::Field;
   582→  ASSERT(current_header_field_.empty());
   583→  ASSERT(current_header_value_.empty());
   584→  return okStatus();
   585→}
