   633→Http::Status ClientConnectionImpl::dispatch(Buffer::Instance& data) {
   634→  Http::Status status = ConnectionImpl::dispatch(data);
   635→  if (status.ok() && data.length() > 0) {
   636→    // The HTTP/1.1 codec pauses dispatch after a single response is complete. Extraneous data
   637→    // after a response is complete indicates an error.
   638→    return codecProtocolError("http/1.1 protocol error: extraneous data after response complete");
   639→  }
   640→  return status;
   641→}
   642→
   643→Http::Status ConnectionImpl::dispatch(Buffer::Instance& data) {
   644→  // Add self to the Dispatcher's tracked object stack.
   645→  ScopeTrackerScopeState scope(this, connection_.dispatcher());
   646→  ENVOY_CONN_LOG(trace, "parsing {} bytes", connection_, data.length());
   647→  // Make sure that dispatching_ is set to false after dispatching, even when
   648→  // http_parser exits early with an error code.
   649→  Cleanup cleanup([this]() { dispatching_ = false; });
   650→  ASSERT(!dispatching_);
   651→  ASSERT(codec_status_.ok());
   652→  ASSERT(buffered_body_.length() == 0);
   653→
   654→  dispatching_ = true;
   655→  onDispatch(data);
   656→  if (maybeDirectDispatch(data)) {
   657→    return Http::okStatus();
   658→  }
   659→
   660→  // Always resume before dispatch.
   661→  parser_->resume();
   662→
   663→  ssize_t total_parsed = 0;
   664→  if (data.length() > 0) {
   665→    current_dispatching_buffer_ = &data;
   666→    while (data.length() > 0) {
   667→      auto slice = data.frontSlice();
   668→      dispatching_slice_already_drained_ = false;
   669→      auto statusor_parsed = dispatchSlice(static_cast<const char*>(slice.mem_), slice.len_);
   670→      if (!statusor_parsed.ok()) {
   671→        return statusor_parsed.status();
   672→      }
   673→      if (!dispatching_slice_already_drained_) {
   674→        ASSERT(statusor_parsed.value() <= slice.len_);
   675→        data.drain(statusor_parsed.value());
   676→      }
   677→
   678→      total_parsed += statusor_parsed.value();
   679→      if (parser_->getStatus() != ParserStatus::Ok) {
   680→        // Parse errors trigger an exception in dispatchSlice so we are guaranteed to be paused at
   681→        // this point.
   682→        ASSERT(parser_->getStatus() == ParserStatus::Paused);
   683→        break;
   684→      }
   685→    }
   686→    current_dispatching_buffer_ = nullptr;
   687→    dispatchBufferedBody();
   688→  } else {
   689→    auto result = dispatchSlice(nullptr, 0);
   690→    if (!result.ok()) {
   691→      return result.status();
   692→    }
   693→  }
   694→  ASSERT(buffered_body_.length() == 0);
   695→
   696→  ENVOY_CONN_LOG(trace, "parsed {} bytes", connection_, total_parsed);
   697→
   698→  // If an upgrade has been handled and there is body data or early upgrade
   699→  // payload to send on, send it on.
   700→  maybeDirectDispatch(data);
   701→  return Http::okStatus();
   702→}
   703→
   704→Envoy::StatusOr<size_t> ConnectionImpl::dispatchSlice(const char* slice, size_t len) {
   705→  ASSERT(codec_status_.ok() && dispatching_);
   706→  const size_t nread = parser_->execute(slice, len);
   707→  if (!codec_status_.ok()) {
   708→    return codec_status_;
   709→  }
   710→
   711→  const ParserStatus status = parser_->getStatus();
   712→  if (status != ParserStatus::Ok && status != ParserStatus::Paused) {
   713→    absl::string_view error = Http1ResponseCodeDetails::get().HttpCodecError;
   714→    if (codec_settings_.use_balsa_parser_) {
   715→      if (parser_->errorMessage() == "headers size exceeds limit" ||
   716→          parser_->errorMessage() == "trailers size exceeds limit") {
   717→        error_code_ = Http::Code::RequestHeaderFieldsTooLarge;
   718→        error = Http1ResponseCodeDetails::get().HeadersTooLarge;
   719→      } else if (parser_->errorMessage() == "header value contains invalid chars") {
   720→        error = Http1ResponseCodeDetails::get().InvalidCharacters;
   721→      }
   722→    }
   723→    RETURN_IF_ERROR(sendProtocolError(error));
   724→    // Avoid overwriting the codec_status_ set in the callbacks.
   725→    ASSERT(codec_status_.ok());
   726→    codec_status_ =
   727→        codecProtocolError(absl::StrCat("http/1.1 protocol error: ", parser_->errorMessage()));
   728→    return codec_status_;
   729→  }
   730→
   731→  return nread;
   732→}
