   780→Status ConnectionImpl::onHeaderFieldImpl(const char* data, size_t length) {
   781→  ASSERT(dispatching_);
   782→
   783→  getBytesMeter().addHeaderBytesReceived(length);
   784→
   785→  // We previously already finished up the headers, these headers are
   786→  // now trailers.
   787→  if (header_parsing_state_ == HeaderParsingState::Done) {
   788→    if (!enableTrailers()) {
   789→      // Ignore trailers.
   790→      return okStatus();
   791→    }
   792→    processing_trailers_ = true;
   793→    header_parsing_state_ = HeaderParsingState::Field;
   794→    allocTrailers();
   795→  }
   796→  if (header_parsing_state_ == HeaderParsingState::Value) {
   797→    RETURN_IF_ERROR(completeCurrentHeader());
   798→  }
   799→
   800→  current_header_field_.append(data, length);
   801→
   802→  return checkMaxHeadersSize();
   803→}
