   805→Status ConnectionImpl::onHeaderValueImpl(const char* data, size_t length) {
   806→  ASSERT(dispatching_);
   807→
   808→  getBytesMeter().addHeaderBytesReceived(length);
   809→
   810→  if (header_parsing_state_ == HeaderParsingState::Done && !enableTrailers()) {
   811→    // Ignore trailers.
   812→    return okStatus();
   813→  }
   814→
   815→  absl::string_view header_value{data, length};
   816→  if (!Http::HeaderUtility::headerValueIsValid(header_value)) {
   817→    ENVOY_CONN_LOG(debug, "invalid header value: {}", connection_, header_value);
   818→    error_code_ = Http::Code::BadRequest;
   819→    RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidCharacters));
   820→    return codecProtocolError("http/1.1 protocol error: header value contains invalid chars");
   821→  }
   822→
   823→  header_parsing_state_ = HeaderParsingState::Value;
   824→  if (current_header_value_.empty()) {
   825→    // Strip leading whitespace if the current header value input contains the first bytes of the
   826→    // encoded header value. Trailing whitespace is stripped once the full header value is known in
   827→    // ConnectionImpl::completeCurrentHeader. http_parser does not strip leading or trailing
   828→    // whitespace as the spec requires: https://tools.ietf.org/html/rfc7230#section-3.2.4 .
   829→    header_value = StringUtil::ltrim(header_value);
   830→  }
   831→  current_header_value_.append(header_value.data(), header_value.length());
   832→
   833→  return checkMaxHeadersSize();
   834→}
