   836→StatusOr<CallbackResult> ConnectionImpl::onHeadersCompleteImpl() {
   837→  ASSERT(!processing_trailers_);
   838→  ASSERT(dispatching_);
   839→  ENVOY_CONN_LOG(trace, "onHeadersCompleteImpl", connection_);
   840→  RETURN_IF_ERROR(completeCurrentHeader());
   841→
   842→  if (!parser_->isHttp11()) {
   843→    // This is not necessarily true, but it's good enough since higher layers only care if this is
   844→    // HTTP/1.1 or not.
   845→    protocol_ = Protocol::Http10;
   846→  }
   847→  RequestOrResponseHeaderMap& request_or_response_headers = requestOrResponseHeaders();
   848→  const Http::HeaderValues& header_values = Http::Headers::get();
   849→  if (Utility::isUpgrade(request_or_response_headers) && upgradeAllowed()) {
   850→    // Ignore h2c upgrade requests until we support them.
   851→    // See https://github.com/envoyproxy/envoy/issues/7161 for details.
   852→    if (absl::EqualsIgnoreCase(request_or_response_headers.getUpgradeValue(),
   853→                               header_values.UpgradeValues.H2c)) {
   854→      ENVOY_CONN_LOG(trace, "removing unsupported h2c upgrade headers.", connection_);
   855→      request_or_response_headers.removeUpgrade();
   856→      if (request_or_response_headers.Connection()) {
   857→        const auto& tokens_to_remove = caseUnorderdSetContainingUpgradeAndHttp2Settings();
   858→        std::string new_value = StringUtil::removeTokens(
   859→            request_or_response_headers.getConnectionValue(), ",", tokens_to_remove, ",");
   860→        if (new_value.empty()) {
   861→          request_or_response_headers.removeConnection();
   862→        } else {
   863→          request_or_response_headers.setConnection(new_value);
   864→        }
   865→      }
   866→      request_or_response_headers.remove(header_values.Http2Settings);
   867→    } else {
   868→      ENVOY_CONN_LOG(trace, "codec entering upgrade mode.", connection_);
   869→      handling_upgrade_ = true;
