1100→Status ServerConnectionImpl::handlePath(RequestHeaderMap& headers, absl::string_view method) {
  1101→  const Http::HeaderValues& header_values = Http::Headers::get();
  1102→  HeaderString path(header_values.Path);
  1103→
  1104→  bool is_connect = (method == header_values.MethodValues.Connect);
  1105→
  1106→  // The url is relative or a wildcard when the method is OPTIONS. Nothing to do here.
  1107→  if (!is_connect && !active_request_->request_url_.getStringView().empty() &&
  1108→      (active_request_->request_url_.getStringView()[0] == '/' ||
  1109→       (method == header_values.MethodValues.Options &&
  1110→        active_request_->request_url_.getStringView()[0] == '*'))) {
  1111→    headers.addViaMove(std::move(path), std::move(active_request_->request_url_));
  1112→    return okStatus();
  1113→  }
  1114→
  1115→  // If absolute_urls and/or connect are not going be handled, copy the url and return.
  1116→  // This forces the behavior to be backwards compatible with the old codec behavior.
  1117→  // CONNECT "urls" are actually host:port so look like absolute URLs to the above checks.
  1118→  // Absolute URLS in CONNECT requests will be rejected below by the URL class validation.
  1119→
  1120→  /**
  1121→   * @param scheme the scheme to validate
  1122→   * @return bool true if the scheme is http.
  1123→   */
  1124→  if (!codec_settings_.allow_absolute_url_ && !is_connect) {
  1125→    headers.addViaMove(std::move(path), std::move(active_request_->request_url_));
  1126→    return okStatus();
  1127→  }
  1128→
  1129→  Utility::Url absolute_url;
  1130→  if (!absolute_url.initialize(active_request_->request_url_.getStringView(), is_connect)) {
  1131→    RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidUrl));
  1132→    return codecProtocolError("http/1.1 protocol error: invalid url in request line");
  1133→  }
  1134→  // RFC7230#5.7
  1135→  // When a proxy receives a request with an absolute-form of
  1136→  // request-target, the proxy MUST ignore the received Host header field
  1137→  // (if any) and instead replace it with the host information of the
  1138→  // request-target. A proxy that forwards such a request MUST generate a
  1139→  // new Host field-value based on the received request-target rather than
  1140→  // forward the received Host field-value.
  1141→  headers.setHost(absolute_url.hostAndPort());
  1142→  // Add the scheme and validate to ensure no https://
  1143→  // requests are accepted over unencrypted connections by front-line Envoys.
  1144→  if (!is_connect) {
  1145→    headers.setScheme(absl::AsciiStrToLower(absolute_url.scheme()));
  1146→    if (!Utility::schemeIsValid(headers.getSchemeValue())) {
  1147→      RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().InvalidScheme));
  1148→      return codecProtocolError("http/1.1 protocol error: invalid scheme");
  1149→    }
  1150→    if (codec_settings_.validate_scheme_ && Utility::schemeIsHttps(absolute_url.scheme()) &&
  1151→        !connection().ssl()) {
  1152→      error_code_ = Http::Code::Forbidden;
  1153→      RETURN_IF_ERROR(sendProtocolError(Http1ResponseCodeDetails::get().HttpsInPlaintext));
  1154→      return codecProtocolError("http/1.1 protocol error: https in the clear");
  1155→    }
  1156→  }
  1157→
  1158→  if (!absolute_url.pathAndQueryParams().empty()) {
  1159→    headers.setPath(absolute_url.pathAndQueryParams());
  1160→  }
  1161→  active_request_->request_url_.clear();
  1162→  return okStatus();
  1163→}
