  1165→Status ServerConnectionImpl::checkProtocolVersion(RequestHeaderMap& headers) {
  1166→  if (protocol() == Protocol::Http10) {
  1167→    // Assume this is HTTP/1.0. This is fine for HTTP/0.9 but this code will also affect any
  1168→    // requests with non-standard version numbers (0.9, 1.3), basically anything which is not
  1169→    // HTTP/1.1.
  1170→    //
  1171→    // The protocol may have shifted in the HTTP/1.0 case so reset it.
  1172→    if (!codec_settings_.accept_http_10_) {
  1173→      // Send "Upgrade Required" if HTTP/1.0 support is not explicitly configured on.
  1174→      error_code_ = Http::Code::UpgradeRequired;
  1175→      RETURN_IF_ERROR(sendProtocolError(StreamInfo::ResponseCodeDetails::get().LowVersion));
  1176→      return codecProtocolError("Upgrade required for HTTP/1.0 or HTTP/0.9");
  1177→    }
  1178→    if (!headers.Host() && !codec_settings_.default_host_for_http_10_.empty()) {
  1179→      // Add a default host if configured to do so.
  1180→      headers.setHost(codec_settings_.default_host_for_http_10_);
  1181→    }
  1182→  }
  1183→  return okStatus();
  1184→}
