  1186→Envoy::StatusOr<CallbackResult> ServerConnectionImpl::onHeadersCompleteBase() {
  1187→  // Handle the case where response happens prior to request complete. It's up to upper layer code
  1188→  // to disconnect the connection but we shouldn't fire any more events since it doesn't make
  1189→  // sense.
  1190→  if (active_request_) {
  1191→    auto& headers = absl::get<RequestHeaderMapPtr>(headers_or_trailers_);
  1192→    ENVOY_CONN_LOG(trace, "Server: onHeadersComplete size={}", connection_, headers->size());
  1193→
  1194→    if (!handling_upgrade_ && headers->Connection()) {
  1195→      // If we fail to sanitize the request, return a 400 to the client
  1196→      if (!Utility::sanitizeConnectionHeader(*headers)) {
  1197→        absl::string_view header_value = headers->getConnectionValue();
  1198→        ENVOY_CONN_LOG(debug, "Invalid nominated headers in Connection: {}", connection_,
  1199→                       header_value);
  1200→        error_code_ = Http::Code::BadRequest;
  1201→        RETURN_IF_ERROR(
  1202→            sendProtocolError(Http1ResponseCodeDetails::get().ConnectionHeaderSanitization));
  1203→        return codecProtocolError("Invalid nominated headers in Connection.");
  1204→      }
  1205→    }
  1206→
  1207→    // Inform the response encoder about any HEAD method, so it can set content
  1208→    // length and transfer encoding headers correctly.
  1209→    const Http::HeaderValues& header_values = Http::Headers::get();
  1210→    active_request_->response_encoder_.setIsResponseToHeadRequest(parser_->methodName() ==
  1211→                                                                  header_values.MethodValues.Head);
  1212→    active_request_->response_encoder_.setIsResponseToConnectRequest(
  1213→        parser_->methodName() == header_values.MethodValues.Connect);
  1214→
  1215→    RETURN_IF_ERROR(handlePath(*headers, parser_->methodName()));
  1216→    ASSERT(active_request_->request_url_.empty());
  1217→
  1218→    headers->setMethod(parser_->methodName());
  1219→    RETURN_IF_ERROR(checkProtocolVersion(*headers));
  1220→
  1221→    // Make sure the host is valid.
  1222→    auto details = HeaderUtility::requestHeadersValid(*headers);
  1223→    if (details.has_value()) {
  1224→      RETURN_IF_ERROR(sendProtocolError(details.value().get()));
  1225→      return codecProtocolError(
  1226→          "http/1.1 protocol error: request headers failed spec compliance checks");
  1227→    }
  1228→
  1229→    // Determine here whether we have a body or not. This uses the new RFC semantics where the
  1230→    // presence of content-length or chunked transfer-encoding indicates a body vs. a particular
  1231→    // method. If there is no body, we defer raising decodeHeaders() until the parser is flushed
  1232→    // with message complete. This allows upper layers to behave like HTTP/2 and prevents a proxy
  1233→    // scenario where the higher layers stream through and implicitly switch to chunked transfer
  1234→    // encoding because end stream with zero body length has not yet been indicated.
  1235→    if (parser_->isChunked() ||
  1236→        (parser_->contentLength().has_value() && parser_->contentLength().value() > 0) ||
  1237→        handling_upgrade_) {
  1238→      active_request_->request_decoder_->decodeHeaders(std::move(headers), false);
  1239→
  1240→      // If the connection has been closed (or is closing) after decoding headers, pause the parser
  1241→      // so we return control to the caller.
  1242→      if (connection_.state() != Network::Connection::State::Open) {
  1243→        return parser_->pause();
  1244→      }
  1245→    } else {
  1246→      deferred_end_stream_headers_ = true;
  1247→    }
  1248→  }
  1249→
  1250→  return CallbackResult::Success;
  1251→}
