  1253→Status ServerConnectionImpl::onMessageBeginBase() {
  1254→  if (!resetStreamCalled()) {
  1255→    ASSERT(active_request_ == nullptr);
  1256→    active_request_ = std::make_unique<ActiveRequest>(*this, std::move(bytes_meter_before_stream_));
  1257→    active_request_->request_decoder_ = &callbacks_.newStream(active_request_->response_encoder_);
  1258→
  1259→    // Check for pipelined request flood as we prepare to accept a new request.
  1260→    // Parse errors that happen prior to onMessageBegin result in stream termination, it is not
  1261→    // possible to overflow output buffers with early parse errors.
  1262→    RETURN_IF_ERROR(doFloodProtectionChecks());
  1263→  }
  1264→  return okStatus();
  1265→}
