  1285→Http::Status ServerConnectionImpl::dispatch(Buffer::Instance& data) {
  1286→  if (abort_dispatch_ != nullptr && abort_dispatch_->shouldShedLoad()) {
  1287→    RETURN_IF_ERROR(sendOverloadError());
  1288→    return envoyOverloadError("Aborting Server Dispatch");
  1289→  }
  1290→
  1291→  if (active_request_ != nullptr && active_request_->remote_complete_) {
  1292→    // Eagerly read disable the connection if the downstream is sending pipelined requests as we
  1293→    // serially process them. Reading from the connection will be re-enabled after the active
  1294→    // request is completed.
  1295→    active_request_->response_encoder_.readDisable(true);
  1296→    return okStatus();
  1297→  }
  1298→
  1299→  Http::Status status = ConnectionImpl::dispatch(data);
  1300→
  1301→  if (active_request_ != nullptr && active_request_->remote_complete_) {
  1302→    // Read disable the connection if the downstream is sending additional data while we are working
  1303→    // on an existing request. Reading from the connection will be re-enabled after the active
  1304→    // request is completed.
  1305→    if (data.length() > 0) {
  1306→      active_request_->response_encoder_.readDisable(true);
  1307→    }
  1308→  }
  1309→  return status;
  1310→}
