  1108→                                             absl::string_view reserved_chars) {
  1109→  absl::flat_hash_set<char> reserved_char_set{reserved_chars.begin(), reserved_chars.end()};
  1110→  for (size_t i = 0; i < value.size(); ++i) {
  1111→    const char& ch = value[i];
  1112→    // The escaping characters are defined in
